/* eslint-disable security/detect-non-literal-fs-filename */
import path from 'node:path';
import fs from 'node:fs';
import fsPromises from 'node:fs/promises';

import { ASSETS_CONFIG } from '@nordic/assets-config';
import { env } from '@nordic/env';

export function getBuildFilePath(fileName: string) {
  return path.resolve(
    __DEV__ && env.BUNDLER_BUILD_ENABLED !== 'true'
      ? ASSETS_CONFIG.PUBLIC_DIR
      : ASSETS_CONFIG.CLIENT_OUTPUT_DIR,
    fileName,
  );
}

export async function readBuildFileContent(fileName: string) {
  const filePath = getBuildFilePath(fileName);

  try {
    const content = await fsPromises.readFile(filePath, 'utf8');

    return content;
  } catch {
    return null;
  }
}

export function readBuildFileContentSync(fileName: string) {
  const filePath = getBuildFilePath(fileName);

  try {
    return fs.readFileSync(filePath, 'utf8');
  } catch {
    return null;
  }
}
